+	}
+	index := readText(t, filepath.Join(outDir, "gmail", "acct_hash", "messages", "index.jsonl"))
+	if !strings.Contains(index, `"markdown":"`+mdRel+`"`) {
+		t.Fatalf("index missing markdown fallback: %s", index)
+	}
+}
